import { useState, useEffect } from 'react';
import { useModel } from '@umijs/max';
import { Card, Form, Input, Button, Typography, Breadcrumb } from 'antd';
import { PageContainer } from '@ant-design/pro-layout';
import { t, urlRenewUpgradeLicense } from '@/global';
import { LicenseModal } from '@/components/LicenseAlert';

const License: React.FC = () => {
  const { initialState } = useModel('@@initialState');
  const { loading, settings: settingsList } = initialState!;
  const [form] = Form.useForm();
  const [showTrigger, setShowTrigger] = useState<number>(0);

  useEffect(() => {
    if (settingsList) {
      const licenseSetting = settingsList.find((entry) => entry.key === 'LICENSE');
      if (licenseSetting) {
        form.setFieldsValue({
          LICENSE: licenseSetting.value,
        });
      }
    }
  }, [settingsList, form]);

  const handleEditLicense = () => {
    setShowTrigger((prevTrigger) => prevTrigger + 1);
  };

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('menu.Settings.License', true) },
        ]} />
      )}
    >
      <LicenseModal once={false} trigger={showTrigger} />
      {loading ? null : (
        <Card>
          <Form form={form}>
            <Form.Item name="LICENSE">
              <Input
                disabled={true}
                suffix={<Typography.Text copyable={{ text: form.getFieldValue('LICENSE') }} />}
              />
            </Form.Item>

            <Button type="primary" onClick={handleEditLicense}>
              {t('Edit')}
            </Button>
            <Button style={{ float: 'right' }} type='primary' onClick={() => window.open(urlRenewUpgradeLicense, '_blank')}>
              {t('Renew / Upgrade License')}
            </Button>
          </Form>
        </Card>
      )}
    </PageContainer>
  );
};

export default License;
